    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
}
.explore-runner-thumb{
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.3s ease;
}
.explore-runner-card:hover .explore-runner-thumb{
    transform: scale(1.04);
}


/* ── Score pill (shared) ── */
.explore-score-pill{
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0.18rem 0.48rem;
    border-radius: 6px;
    border: 1px solid var(--border-card);
    background-color: var(--bg-pill);
    color: var(--text-faint);
    font-family: var(--font-ui);
    font-size: 0.58rem;
    font-weight: 650;
    line-height: 1;
    letter-spacing: 0.02rem;
    white-space: nowrap;
}

/* ── Meta right (search mode) ── */
.explore-meta-right{
    display: flex;
    align-items: center;
    gap: 0.35rem;
    margin-left: auto;
}

/* ── Explore rank (search mode) ── */
.explore-rank{
    display: flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    padding: 0.15rem 1.15rem 0;
    box-sizing: border-box;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.15rem;
    font-weight: 800;
    line-height: 1;
    color: var(--border-card);
    user-select: none;
}
.explore-page-container .cards:nth-child(-n+3) .explore-rank{
    color: var(--accent-amber);
}

/* ── Fix border stacking in search mode ── */
.explore-page-container .card-image-banner{
    border-bottom: none;
}
.explore-page-container .card-icons-container{
    border-top: none;
}

/* ── Explore cards container (search mode fallback) ── */
.explore-postcards-parent-container{
    top: 0;
}


/* ══════════════════════════════════════════
   MOBILE
   ══════════════════════════════════════════ */
@media (max-width: 480px){
    .explore-page-container{
        padding-bottom: 5.5rem;
    }

    .explore-page-container .search-shell{
        top: 0;
    }

    .explore-section-title{
        font-size: 0.62rem;
        padding: 0.6rem 0.6rem 0.4rem 0.6rem;
        letter-spacing: 0.06rem;
    }

    /* ── Hero mobile ── */
    .explore-hero-section{
        padding: 0 6px;
    }
    .explore-hero-card{
        border-radius: 10px;
    }
    .explore-hero-glow{
        inset: -14px;
        border-radius: 24px;
        filter: blur(14px);
    }
    .explore-hero-image-wrap{
        max-height: 180px;
    }
    .explore-hero-image{
        max-height: 180px;
    }
    .explore-hero-body{
        padding: 0.85rem 0.85rem 0.8rem 0.85rem;
        gap: 0.5rem;
    }
    .explore-hero-body--has-image{
        margin-top: -2rem;
    }
    .explore-hero-badge{
        padding: 0.2rem 0.55rem 0.2rem 0.3rem;
    }
    .explore-hero-flame{
        width: 14px;
        height: 14px;
    }
    .explore-hero-badge-text{
        font-size: 0.58rem;
    }
    .explore-hero-title{
        font-size: 1.1rem;
        line-height: 1.25;
    }
    .explore-hero-excerpt{
        font-size: 0.8rem;
        line-height: 1.5;
        -webkit-line-clamp: 2;
    }
    .explore-hero-footer{
        gap: 0.4rem;
        padding-top: 0.45rem;
    }
    .explore-hero-author .user-info-avatar{
        width: 20px;
        height: 20px;
    }
    .explore-hero-author .user-newsfeed-name{
        font-size: 0.72rem;
        max-width: 110px;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
    }
    .explore-hero-author .user-post-date{
        font-size: 0.6rem;
    }
    .explore-hero-score-pill{
        font-size: 0.56rem;
        padding: 0.18rem 0.4rem;
    }
    .explore-hero-score-flame{
        width: 10px;
        height: 10px;
    }

    /* ── Runner cards mobile ── */
    .explore-runners-list{
        gap: 2px;
        padding: 0 6px;
        padding-bottom: 6rem;    
    }
    .explore-runner-card{
        border-radius: 10px;
    }
    .explore-runner-rank-col{
        width: 30px;
        padding-top: 0.8rem;
    }
    .explore-runner-rank{
        font-size: 0.95rem;
    }
    .explore-runner-body{
        padding: 0.7rem 0.4rem 0.6rem 0;
        gap: 0.2rem;
    }
    .explore-runner-title{
        font-size: 0.84rem;
        line-height: 1.25;
    }
    .explore-runner-excerpt{
        font-size: 0.74rem;
        -webkit-line-clamp: 1;
    }
    .explore-runner-meta{
        gap: 0.3rem;
        padding-top: 0.25rem;
    }
    .explore-runner-author .user-info-avatar{
        width: 18px;
        height: 18px;
    }
    .explore-runner-author .user-newsfeed-name{
        font-size: 0.68rem;
        max-width: 90px;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
    }
    .explore-runner-author .user-post-date{
        font-size: 0.58rem;
    }
    .explore-runner-thumb-wrap{
        width: 70px;
    }

    /* ── Search mode cards mobile ── */
    .explore-postcards-parent-container{
        top: 0;
    }
    .explore-rank{
        font-size: 1rem;
        padding: 0.1rem 0.75rem 0;
    }
    .explore-meta-right{
        gap: 0.25rem;
    }
    .explore-score-pill{
        font-size: 0.54rem;
        padding: 0.15rem 0.38rem;
    }
}

